function normalizeHiddenAssetRefs(values){if(!Array.isArray(values))return[];return [...new Set(values.map(value=>String(value||'').trim().toLowerCase()).filter(value=>/^(ethereum|base|polygon):[^\s:]+$/.test(value)).slice(0,500))]}
function applyHiddenAssetRefs(values){hiddenAssets.clear();normalizeHiddenAssetRefs(values).forEach(value=>hiddenAssets.add(value));if(hiddenAssets.size)localStorage.setItem('cultFundsHiddenAssets',JSON.stringify([...hiddenAssets]));else localStorage.removeItem('cultFundsHiddenAssets');const hint=document.querySelector('#hidden-assets-hint');if(hint)hint.textContent=hiddenAssets.size?`${hiddenAssets.size} asset${hiddenAssets.size===1?'':'s'} hidden locally.`:'No manually hidden assets.'}
