function normalizePrivateIdentities(value){const identities={};if(!value||typeof value!=='object')return identities;Object.entries(value).forEach(([address,fields])=>{if(!ethers.utils.isAddress(address))return;const record={name:String(fields?.name||'').trim().slice(0,60),description:String(fields?.description||'').trim().slice(0,240),labels:normalizeIdentityLabels(fields?.labels),updatedAt:Number(fields?.updatedAt)||Date.now()};if(record.name||record.description||record.labels.length)identities[address.toLowerCase()]=record});return identities}
function normalizeWalletList(wallets){if(!Array.isArray(wallets))return[];const seen=new Set;return wallets.filter(wallet=>wallet&&ethers.utils.isAddress(wallet.address||'')).map(wallet=>{const normalized={address:ethers.utils.getAddress(wallet.address),label:String(wallet.label||'').slice(0,60),note:String(wallet.note||'').slice(0,240)};const labels=normalizeIdentityLabels(wallet.labels);if(labels.length)normalized.labels=labels;return normalized}).filter(wallet=>{const key=wallet.address.toLowerCase();if(seen.has(key))return false;seen.add(key);return true})}
