function normalizeDaoPreset(value){if(!value)return null;let source=value;let version=String(value.version||'').trim();let snapshotDate=String(value.snapshotDate||'');if(Array.isArray(value.walletSets)&&value.walletSets.length){source=value.walletSets.find(set=>String(set.id)==='dao-funds')||value.walletSets.find(set=>String(set.id)===String(value.activeWalletSetId||''))||value.walletSets[0];const exportedAt=String(value.exportedAt||'').trim();version=exportedAt?`export:${exportedAt}`:String(source.presetVersion||value.version||'').trim();snapshotDate=(exportedAt.match(/^\d{4}-\d{2}-\d{2}/)||[])[0]||String(source.presetSnapshotDate||'')}if(!version)return null;const wallets=normalizeWalletList(source.wallets);if(!wallets.length)return null;const hiddenSource=Array.isArray(source.hiddenAssets)?source.hiddenAssets:value.hiddenAssets;return{version,snapshotDate,name:'CULTDAO Funds',showTreasury:source.showTreasury!==false,wallets,hiddenAssets:normalizeHiddenAssetRefs(hiddenSource)}}
