function showDaoPresetUpdateDialog(){if(!availableDaoPreset)return;const dialog=document.querySelector('#dao-preset-update-dialog');if(!dialog||(!dialog.open&&document.querySelector('dialog[open]')))return;const copy=document.querySelector('#dao-preset-update-copy');if(copy)copy.textContent=`A newer one-time CULTDAO Funds snapshot from ${formatDaoSnapshotDate(availableDaoPreset.snapshotDate)} is available. Update the local CULTDAO Funds collection now?`;if(!dialog.open)dialog.showModal()}
