async function checkDaoPresetUpdate(){try{const preset=await fetchPublishedDaoPreset();if(!preset)return;const dao=state.walletSets.find(set=>set.id==='dao-funds');if(!dao)return;if(!dao.presetVersion){dao.name=preset.name;dao.showTreasury=preset.showTreasury;dao.presetVersion=preset.version;dao.presetSnapshotDate=preset.snapshotDate;dao.presetAddresses=preset.wallets.map(wallet=>wallet.address);dao.presetWallets=preset.wallets.map(wallet=>({...wallet}));applyHiddenAssetRefs(preset.hiddenAssets||[]);saveWalletSets();renderWalletSetControls();return}if(dao.presetVersion===preset.version){if(!dao.presetAddresses?.length)dao.presetAddresses=preset.wallets.map(wallet=>wallet.address);if(!dao.presetWallets?.length)dao.presetWallets=preset.wallets.map(wallet=>({...wallet}));dao.presetSnapshotDate=preset.snapshotDate;saveWalletSets();renderWalletSetControls();return}markDaoPresetAvailable(preset);if(localStorage.getItem(DAO_PRESET_DISMISSED_KEY)!==preset.version)showDaoPresetUpdateDialog()}catch(error){console.warn('CULTDAO Funds preset check unavailable',error)}}
async function applyDaoPresetUpdate(event){event?.preventDefault();const preset=availableDaoPreset;if(!preset)return;const dao=state.walletSets.find(set=>set.id==='dao-funds');if(!dao)return;const updateButton=event?.submitter;if(updateButton?.disabled)return;if(updateButton)updateButton.disabled=true;try{await requirePortfolioSafetyBackup('portfolio-preset-update')}catch(error){if(updateButton)updateButton.disabled=false;toast(error?.message||'Safety backup failed; update stopped');return}const currentByAddress=new Map(dao.wallets.map(wallet=>[wallet.address.toLowerCase(),wallet]));const previousOfficial=normalizeWalletList(dao.presetWallets||[]);const previousByAddress=new Map(previousOfficial.map(wallet=>[wallet.address.toLowerCase(),wallet]));const previousAddresses=new Set((dao.presetAddresses?.length?dao.presetAddresses:previousOfficial.map(wallet=>wallet.address)).map(address=>address.toLowerCase()));const nextAddresses=new Set(preset.wallets.map(wallet=>wallet.address.toLowerCase()));const mergedOfficial=preset.wallets.map(wallet=>{const existing=currentByAddress.get(wallet.address.toLowerCase());const previous=previousByAddress.get(wallet.address.toLowerCase());if(!existing)return{...wallet};const preserveLabel=!previous||existing.label!==previous.label;const preserveNote=!previous||existing.note!==previous.note;return{...wallet,label:preserveLabel?existing.label:wallet.label,note:preserveNote?existing.note:wallet.note}});const localAdditions=dao.wallets.filter(wallet=>!previousAddresses.has(wallet.address.toLowerCase())&&!nextAddresses.has(wallet.address.toLowerCase()));dao.name=preset.name;dao.showTreasury=preset.showTreasury;dao.wallets=normalizeWalletList([...mergedOfficial,...localAdditions]);dao.presetVersion=preset.version;dao.presetSnapshotDate=preset.snapshotDate;dao.presetAddresses=preset.wallets.map(wallet=>wallet.address);dao.presetWallets=preset.wallets.map(wallet=>({...wallet}));applyHiddenAssetRefs(preset.hiddenAssets||[]);localStorage.removeItem(DAO_PRESET_DISMISSED_KEY);document.querySelector('#dao-preset-update-dialog')?.close();document.querySelector('#dao-preset-update')?.setAttribute('hidden','');availableDaoPreset=null;if(state.activeWalletSetId==='dao-funds'){state.wallets=dao.wallets;state.data.clear();localStorage.setItem('cultFundsWallets',JSON.stringify(dao.wallets))}saveWalletSets();renderWalletSetControls();render();toast('CULTDAO Funds snapshot updated');if(state.activeWalletSetId==='dao-funds'&&state.wallets.length)await refresh()}
