async function importLocalSetup(file){if(!file)return;try{const parsed=JSON.parse(await file.text());const imported=normalizeImportedWalletSets(parsed);if(!confirm(`Import ${imported.sets.length} wallet collection${imported.sets.length===1?'':'s'}? This replaces the local collections and labels in this browser.`))return;state.walletSets=imported.sets;state.activeWalletSetId=imported.activeId;state.wallets=state.walletSets.find(set=>set.id===state.activeWalletSetId)?.wallets||[];state.data.clear();Object.keys(ownerAliases).forEach(key=>delete ownerAliases[key]);if(parsed.ownerAliases&&typeof parsed.ownerAliases==='object')Object.entries(parsed.ownerAliases).forEach(([address,label])=>{if(ethers.utils.isAddress(address)&&String(label||'').trim())ownerAliases[address.toLowerCase()]=String(label).trim().slice(0,60)});saveOwnerAliases();if(Array.isArray(parsed.hiddenAssets))applyHiddenAssetRefs(parsed.hiddenAssets);if(currencies[parsed.currency]){state.currency=parsed.currency;localStorage.setItem('fundsCurrency',state.currency);document.querySelector('#currency').value=state.currency}localStorage.removeItem(PORTFOLIO_CACHE_KEY);Object.keys(portfolioCacheStore).forEach(key=>delete portfolioCacheStore[key]);saveWalletSets();if(state.activeWalletSetId==='dao-funds')localStorage.setItem('cultFundsWallets',JSON.stringify(state.wallets));renderWalletSetControls();render();toast('Local setup imported');if(state.wallets.length)await refresh()}catch(error){toast(error instanceof SyntaxError?'Invalid JSON file':error.message||'Could not import setup')}finally{const input=document.querySelector('#import-data-file');if(input)input.value=''}}
