const portfolioCacheStore=loadPortfolioCacheStore();
function saveActivePortfolioCache(){try{const addresses=new Set(state.wallets.map(wallet=>wallet.address.toLowerCase()));const rows=[...state.data.entries()].filter(([key])=>addresses.has(key.slice(0,key.lastIndexOf(':')).toLowerCase())).map(([key,row])=>[key,{...row,safe:row.safe?{...row.safe,pending:row.safe.pending?{...row.safe.pending,items:(row.safe.pending.items||[]).slice(0,12)}:null}:null}]);portfolioCacheStore[state.activeWalletSetId]={savedAt:Date.now(),currency:state.currency,rows,prices:state.prices,legacyRvltUnitPrice:state.legacyRvltUnitPrice,enaUnitPrice:state.enaUnitPrice,treasuryCult:state.treasuryCult,treasuryValueEth:state.treasuryValueEth};localStorage.setItem(PORTFOLIO_CACHE_KEY,JSON.stringify(portfolioCacheStore))}catch(error){console.warn('Portfolio cache unavailable',error)}}
function restorePortfolioCacheForSet(setId=state.activeWalletSetId){const cached=portfolioCacheStore[setId];if(!cached||cached.currency!==state.currency||!Array.isArray(cached.rows))return false;const set=state.walletSets.find(item=>item.id===setId);const addresses=new Set((set?.wallets||[]).map(wallet=>wallet.address.toLowerCase()));state.prices=cached.prices||{};state.legacyRvltUnitPrice=Number(cached.legacyRvltUnitPrice)||0;state.enaUnitPrice=Number(cached.enaUnitPrice)||0;state.data=new Map(cached.rows.filter(([key,row])=>row&&CHAINS[row.chain]&&addresses.has(key.slice(0,key.lastIndexOf(':')).toLowerCase())).map(([key,row])=>[key,{...row,assets:(row.assets||[]).map(asset=>assetKey(asset)===LEGACY_RVLT_REF?{...asset,value:state.legacyRvltUnitPrice>0?(asset.amount||0)*state.legacyRvltUnitPrice:0,priced:state.legacyRvltUnitPrice>0}:assetKey(asset)===ENA_REF&&state.enaUnitPrice>0?{...asset,value:(asset.amount||0)*state.enaUnitPrice,priced:true}:asset)}]));state.treasuryCult=cached.treasuryCult??null;state.treasuryValueEth=cached.treasuryValueEth??null;return state.data.size>0}
