function renderWalletSetControls(){const select=document.querySelector('#wallet-set-select');if(!select)return;const options=state.walletSets.map(set=>`<option value="${escapeAttr(set.id)}">${escapeHtml(set.name)} · ${set.wallets.length}${set.private?' · Private':''}</option>`).join('');select.innerHTML=options;select.value=state.activeWalletSetId;const quick=document.querySelector('#hero-wallet-set-select');const quickWrap=document.querySelector('#hero-wallet-set-switch');if(quick){quick.innerHTML=options;quick.value=state.activeWalletSetId}if(quickWrap)quickWrap.hidden=state.walletSets.length<2;const active=state.walletSets.find(set=>set.id===state.activeWalletSetId);document.querySelector('#delete-wallet-set').disabled=!active||active.id==='dao-funds';document.querySelector('.hero')?.classList.toggle('personal-wallet-set',!active?.showTreasury);if(active?.private&&localStorage.getItem('cultHubPortfolioSummary:v1'))localStorage.removeItem('cultHubPortfolioSummary:v1');renderDaoPresetDescription();window.dispatchEvent(new CustomEvent('cult-hub-portfolio-collections',{detail:{activeId:state.activeWalletSetId,private:Boolean(active?.private)}}))}
