function saveWalletSetDialog(event){event.preventDefault();const name=document.querySelector('#wallet-set-name').value.trim();if(!name)return;const showTreasury=document.querySelector('#wallet-set-dialog-treasury').checked;const isPrivate=document.querySelector('#wallet-set-dialog-private').checked;if(editingWalletSetId){const set=state.walletSets.find(item=>item.id===editingWalletSetId);if(set){set.name=name.slice(0,40);set.showTreasury=showTreasury;set.private=set.id==='dao-funds'?false:isPrivate;saveWalletSets();toast('Wallet collection updated')}}else{save();const set={id:`set-${Date.now().toString(36)}-${Math.random().toString(36).slice(2,7)}`,name:name.slice(0,40),wallets:[],showTreasury,private:isPrivate};state.walletSets.push(set);state.activeWalletSetId=set.id;state.wallets=set.wallets;state.data.clear();saveWalletSets();toast(`${set.name} collection created`)}document.querySelector('#wallet-set-dialog').close();editingWalletSetId=null;renderWalletSetControls();render()}
