function short(a){return `${a.slice(0,6)}…${a.slice(-4)}`}
function cachedEnsName(address){const entry=ensCache[String(address||'').toLowerCase()];return typeof entry?.name==='string'?entry.name:''}
function saveEnsCache(){localStorage.setItem(ENS_CACHE_KEY,JSON.stringify(ensCache))}
function ensAddressesInView(){const addresses=new Set(state.wallets.map(wallet=>wallet.address.toLowerCase()));const active=new Set(state.wallets.map(wallet=>wallet.address.toLowerCase()));state.data.forEach((row,key)=>{const walletAddress=key.slice(0,key.lastIndexOf(':')).toLowerCase();if(!active.has(walletAddress))return;(row.safe?.owners||[]).forEach(owner=>addresses.add(owner.toLowerCase()))});return [...addresses].filter(address=>ethers.utils.isAddress(address))}
function scheduleEnsLookup(){clearTimeout(ensLookupTimer);ensLookupTimer=setTimeout(()=>scanEnsNames().catch(error=>console.warn('ENS reverse-name scan unavailable',error)),350)}
async function scanEnsNames(){
  if(ensLookupRunning)return;
  const now=Date.now();
  const pending=ensAddressesInView().filter(address=>!ensCache[address]||now-Number(ensCache[address].checkedAt||0)>ENS_CACHE_TTL);
  const aliasesStale=now-ensAliasCheckedAt>ENS_CACHE_TTL;
  if(!pending.length&&!aliasesStale)return;
  ensLookupRunning=true;
  try{
    const provider=await providerFor('ethereum');
    for(let index=0;index<pending.length;index+=3){
      const batch=pending.slice(index,index+3);
      await Promise.all(batch.map(async address=>{
        let name='';
        try{name=await withTimeout(provider.lookupAddress(address),7000,`ENS lookup ${short(address)}`)||''}
        catch(error){console.warn(`ENS lookup unavailable for ${short(address)}`,error)}
        ensCache[address]={name,checkedAt:Date.now()};
      }));
      saveEnsCache();
      decorateEnsNames();
      await wait(100);
    }
    if(aliasesStale){
      await Promise.all(KNOWN_DAO_ENS_NAMES.map(async name=>{
        try{
          const address=await withTimeout(provider.resolveName(name),7000,`ENS alias ${name}`);
          if(address&&ethers.utils.isAddress(address)){
            const key=address.toLowerCase();
            if(!ensCache[key]?.name)ensCache[key]={name,checkedAt:Date.now()};
          }
        }catch(error){console.warn(`ENS alias unavailable for ${name}`,error)}
      }));
      ensAliasCheckedAt=Date.now();
      localStorage.setItem(ENS_ALIAS_CACHE_KEY,String(ensAliasCheckedAt));
      saveEnsCache();
      decorateEnsNames();
      decorateCopyableAddresses();
    }
  }finally{ensLookupRunning=false}
}
function walletAnchor(address){return `wallet-${String(address).toLowerCase()}`}
function money(n){const value=Number(n)||0;const comparison={btc:['BTC',8],eth:['ETH',6],xau:['XAU',6],xag:['XAG',4],cult:['CULT',2]};if(comparison[state.currency]){const [unit,digits]=comparison[state.currency];return `${value.toLocaleString(undefined,{maximumFractionDigits:digits})} ${unit}`}return new Intl.NumberFormat(undefined,{style:'currency',currency:state.currency.toUpperCase(),maximumFractionDigits:value<1?4:2}).format(value)}
function assetUnitPrice(asset){if(!asset?.priced||!(asset.amount>0)||!(asset.value>0))return '—';const value=asset.value/asset.amount;const units={btc:'BTC',eth:'ETH',xau:'XAU',xag:'XAG',cult:'CULT'};if(units[state.currency])return `${value.toLocaleString(undefined,{maximumSignificantDigits:5})} ${units[state.currency]}`;return new Intl.NumberFormat(undefined,{style:'currency',currency:state.currency.toUpperCase(),maximumSignificantDigits:5}).format(value)}
function visualNumberMarkup(value,{minimumFractionDigits=2,maximumFractionDigits=2}={}){const amount=Math.abs(Number(value)||0);let fixed=amount===0?'0':amount.toFixed(maximumFractionDigits);if(amount!==0&&maximumFractionDigits>minimumFractionDigits){const [integer,fraction='']=fixed.split('.');fixed=`${integer}.${fraction.replace(/0+$/,'').padEnd(minimumFractionDigits,'0')}`}const [integer,fraction='']=fixed.split('.');const first=integer.length%3||3;const groups=[integer.slice(0,first)];for(let index=first;index<integer.length;index+=3)groups.push(integer.slice(index,index+3));const sign=Number(value)<0?'-':'';return `${sign}${groups.map(group=>`<span class="number-group">${group}</span>`).join('')}${fraction?`<span class="number-decimal">.${fraction}</span>`:''}`}
function heroValueMarkup(value){const units={btc:['BTC',8],eth:['ETH',6],xau:['XAU',6],xag:['XAG',4],cult:['CULT',2]};let unit,digits=2;if(units[state.currency]){[unit,digits]=units[state.currency]}else{unit=new Intl.NumberFormat(undefined,{style:'currency',currency:state.currency.toUpperCase()}).formatToParts(0).find(part=>part.type==='currency')?.value||state.currency.toUpperCase()}const useBillions=Math.abs(value)>=1e9;return `${visualNumberMarkup(useBillions?value/1e9:value,{minimumFractionDigits:2,maximumFractionDigits:useBillions?2:digits})}${useBillions?'<span class="number-suffix">B</span>':''}<span class="number-unit">${escapeHtml(unit)}</span>`}
function assetAmountDisplay(assetOrAmount){const asset=typeof assetOrAmount==='object'&&assetOrAmount?assetOrAmount:{amount:assetOrAmount,symbol:''};const value=Number(asset.amount)||0;if(Math.abs(value)>=1e9)return `${visualNumberMarkup(value/1e9)}<span class="number-suffix">B</span>`;const symbol=String(asset.symbol||'').toUpperCase();const maximumFractionDigits=/^(W?BTC|W?ETH|XAU|XAG)$/.test(symbol)?4:2;return visualNumberMarkup(value,{minimumFractionDigits:2,maximumFractionDigits})}
function assetOverviewThreshold(){return ASSET_THRESHOLD_LEVELS[state.assetThresholdIndex]||0}
function toast(s){const e=document.querySelector('#toast');e.textContent=s;e.classList.add('show');setTimeout(()=>e.classList.remove('show'),1600)}
const wait=milliseconds=>new Promise(resolve=>setTimeout(resolve,milliseconds));
const withTimeout=(promise,milliseconds,label='Request')=>Promise.race([promise,new Promise((_,reject)=>setTimeout(()=>reject(new Error(`${label} timed out`)),milliseconds))]);
async function fetchWithRetry(url,options={},attempts=3,timeoutMs=8000){let response;for(let attempt=0;attempt<attempts;attempt+=1){const controller=new AbortController;const timeout=setTimeout(()=>controller.abort(),timeoutMs);try{response=await fetch(url,{...options,signal:options.signal||controller.signal});if(response.ok||![429,500,502,503,504].includes(response.status))return response}catch(error){if(attempt===attempts-1)throw error}finally{clearTimeout(timeout)}if(attempt<attempts-1){const retryAfter=Number(response?.headers?.get('retry-after'));await wait(Number.isFinite(retryAfter)&&retryAfter>0?retryAfter*1000:700*(attempt+1))}}return response}
async function providerFor(chain){for(const url of CHAINS[chain].rpc){try{const p=new ethers.providers.JsonRpcProvider(url);await withTimeout(p.getBlockNumber(),6000,`${CHAINS[chain].name} RPC`);return p}catch{}}throw new Error(`No ${CHAINS[chain].name} RPC available`)}
async function fetchTreasuryCultValue(){const provider=await providerFor('ethereum');const cult=new ethers.Contract(CULT_TOKEN_ADDRESS,['function balanceOf(address) view returns (uint256)'],provider);const pair=new ethers.Contract(CULT_WETH_PAIR_ADDRESS,['function token0() view returns (address)','function getReserves() view returns (uint112 reserve0,uint112 reserve1,uint32 blockTimestampLast)'],provider);const [treasuryRaw,token0,reserves]=await Promise.all([withTimeout(cult.balanceOf(CULT_TREASURY_ADDRESS),7000,'Treasury CULT balance'),withTimeout(pair.token0(),7000,'CULT pair token'),withTimeout(pair.getReserves(),7000,'CULT pair reserves')]);const cultIsToken0=token0.toLowerCase()===CULT_TOKEN_ADDRESS.toLowerCase();const cultReserve=Number(ethers.utils.formatUnits(cultIsToken0?reserves.reserve0:reserves.reserve1,18));const ethReserve=Number(ethers.utils.formatUnits(cultIsToken0?reserves.reserve1:reserves.reserve0,18));const cultInEth=cultReserve>0?ethReserve/cultReserve:0;state.treasuryCult=Number(ethers.utils.formatUnits(treasuryRaw,18));state.treasuryValueEth=state.treasuryCult*cultInEth;render()}
async function fetchPrices(){const ids=[...new Set([...Object.values(CHAINS).map(c=>c.price),'cult-dao',...Object.values(TRUSTED_PRICE_IDS)])].join(',');const vs='usd,eur,gbp,jpy,aud,cad,chf,btc,eth,xau,xag';const r=await fetch(`https://api.coingecko.com/api/v3/simple/price?ids=${ids}&vs_currencies=${vs}`);if(!r.ok)throw new Error('Price service unavailable');state.prices=await r.json()}
function currencyRate(currency=state.currency){if(currency==='usd')return 1;if(currency==='cult'){const cultUsd=state.prices['cult-dao']?.usd||0;return cultUsd>0?1/cultUsd:0}const eth=state.prices.ethereum||{};return eth.usd>0&&eth[currency]>0?eth[currency]/eth.usd:0}
function fiatRate(){return currencyRate()||1}
function rescalePortfolioValues(ratio){if(!(ratio>0)||!Number.isFinite(ratio)||ratio===1)return;state.data.forEach(row=>{row.assets=(row.assets||[]).map(asset=>asset.priced?{...asset,value:(asset.value||0)*ratio}:asset)});state.legacyRvltUnitPrice*=ratio;state.enaUnitPrice*=ratio}
function unitPrice(coinId){const quote=state.prices[coinId]||{};if(state.currency==='cult')return (quote.usd||0)*fiatRate();return quote[state.currency]||quote.usd||0}
async function fetchLegacyRvltPrice(){try{const provider=await providerFor('polygon');const pair=new ethers.Contract(LEGACY_RVLT_PAIR,['function token0() view returns (address)','function token1() view returns (address)','function getReserves() view returns (uint112 reserve0,uint112 reserve1,uint32 blockTimestampLast)'],provider);const [token0,token1,reserves]=await Promise.all([withTimeout(pair.token0(),7000,'Legacy RVLT pool token0'),withTimeout(pair.token1(),7000,'Legacy RVLT pool token1'),withTimeout(pair.getReserves(),7000,'Legacy RVLT pool reserves')]);const legacy=LEGACY_RVLT_REF.split(':')[1].toLowerCase();const quote=LEGACY_RVLT_QUOTE.toLowerCase();const first=token0.toLowerCase();const second=token1.toLowerCase();if(!((first===quote&&second===legacy)||(first===legacy&&second===quote)))throw new Error('Legacy RVLT pool token pair changed');const quoteReserve=first===quote?reserves.reserve0:reserves.reserve1;const legacyReserve=first===legacy?reserves.reserve0:reserves.reserve1;const quoteAmount=Number(ethers.utils.formatUnits(quoteReserve,18));const legacyAmount=Number(ethers.utils.formatUnits(legacyReserve,18));const quotePrice=unitPrice('ethereum');const poolPrice=legacyAmount>0&&quotePrice>0?(quoteAmount/legacyAmount)*quotePrice:0;if(!(poolPrice>0))throw new Error('Legacy RVLT pool price unavailable');state.legacyRvltUnitPrice=poolPrice}catch(error){state.legacyRvltUnitPrice=0;console.warn('Legacy RVLT pool price unavailable; showing the balance as unpriced',error)}}
async function fetchEnaPoolPrice(){try{const provider=await providerFor('ethereum');const pool=new ethers.Contract(ENA_WETH_POOL_ADDRESS,['function token0() view returns (address)','function slot0() view returns (uint160 sqrtPriceX96,int24 tick,uint16 observationIndex,uint16 observationCardinality,uint16 observationCardinalityNext,uint8 feeProtocol,bool unlocked)'],provider);const [token0,slot0]=await Promise.all([withTimeout(pool.token0(),7000,'ENA pool token0'),withTimeout(pool.slot0(),7000,'ENA pool price')]);if(token0.toLowerCase()!==ENA_TOKEN_ADDRESS)throw new Error('ENA pool token order changed');const ethPrice=unitPrice('ethereum');const wethPerEna=Math.pow(1.0001,Number(slot0.tick??slot0[1]));const price=wethPerEna*ethPrice;if(!(price>0)||!Number.isFinite(price))throw new Error('ENA pool price unavailable');state.enaUnitPrice=price}catch(error){state.enaUnitPrice=0;console.warn('Live ENA pool price unavailable; falling back to indexed price',error)}}
function sqrtRatioAtTick(tick){if(tick< -887272||tick>887272)throw new Error('Invalid LP tick');const absTick=BigInt(tick<0?-tick:tick);let ratio=(absTick&1n)!==0n?TICK_CONSTANTS[0]:0x100000000000000000000000000000000n;for(let index=1;index<TICK_CONSTANTS.length;index+=1)if((absTick&(1n<<BigInt(index)))!==0n)ratio=(ratio*TICK_CONSTANTS[index])>>128n;if(tick>0)ratio=MAX_UINT256/ratio;const remainder=ratio&((1n<<32n)-1n);return (ratio>>32n)+(remainder===0n?0n:1n)}
function amount0ForLiquidity(sqrtA,sqrtB,liquidity){if(sqrtA>sqrtB)[sqrtA,sqrtB]=[sqrtB,sqrtA];return ((liquidity<<96n)*(sqrtB-sqrtA))/sqrtB/sqrtA}
function amount1ForLiquidity(sqrtA,sqrtB,liquidity){if(sqrtA>sqrtB)[sqrtA,sqrtB]=[sqrtB,sqrtA];return liquidity*(sqrtB-sqrtA)/Q96}
function amountsForLiquidity(sqrtPrice,sqrtA,sqrtB,liquidity){if(sqrtA>sqrtB)[sqrtA,sqrtB]=[sqrtB,sqrtA];if(sqrtPrice<=sqrtA)return{amount0:amount0ForLiquidity(sqrtA,sqrtB,liquidity),amount1:0n};if(sqrtPrice<sqrtB)return{amount0:amount0ForLiquidity(sqrtPrice,sqrtB,liquidity),amount1:amount1ForLiquidity(sqrtA,sqrtPrice,liquidity)};return{amount0:0n,amount1:amount1ForLiquidity(sqrtA,sqrtB,liquidity)}}
async function lpTokenInfo(provider,address,chain='ethereum'){const lower=address.toLowerCase();const token=new ethers.Contract(address,['function symbol() view returns (string)','function decimals() view returns (uint8)'],provider);const [symbol,decimals]=await Promise.all([withTimeout(token.symbol(),7000,'LP token symbol').catch(()=>short(address)),withTimeout(token.decimals(),7000,'LP token decimals').catch(()=>18)]);let price=chain==='ethereum'&&lower===ENA_TOKEN_ADDRESS?state.enaUnitPrice:chain==='ethereum'&&lower===WETH_TOKEN_ADDRESS?unitPrice('ethereum'):chain==='ethereum'&&lower===CULT_TOKEN_ADDRESS?unitPrice('cult-dao'):chain==='ethereum'&&lower===DCULT_TOKEN_ADDRESS?unitPrice('cult-dao'):0;if(!(price>0))state.data.forEach(row=>(row.assets||[]).forEach(asset=>{if(asset.chain===chain&&String(asset.address||'').toLowerCase()===lower&&asset.amount>0&&asset.value>0)price=asset.value/asset.amount}));if(!(price>0)){try{const response=await fetchWithRetry(`${CHAINS[chain].indexer}/api/v2/tokens/${address}`,{},1,7000);if(response.ok){const metadata=await response.json();const indexedUsd=Number(metadata.exchange_rate||0);if(indexedUsd>0)price=indexedUsd*fiatRate()}}catch{}}return{address:lower,symbol:String(symbol),decimals:Number(decimals),price}}
async function fetchV3LpAssets(provider,address){const positionManager=new ethers.Contract(UNISWAP_V3_POSITION_MANAGER,['function balanceOf(address owner) view returns (uint256)','function tokenOfOwnerByIndex(address owner,uint256 index) view returns (uint256)','function positions(uint256 tokenId) view returns (uint96 nonce,address operator,address token0,address token1,uint24 fee,int24 tickLower,int24 tickUpper,uint128 liquidity,uint256 feeGrowthInside0LastX128,uint256 feeGrowthInside1LastX128,uint128 tokensOwed0,uint128 tokensOwed1)','function collect((uint256 tokenId,address recipient,uint128 amount0Max,uint128 amount1Max) params) payable returns (uint256 amount0,uint256 amount1)'],provider);const count=Math.min(24,Number(await withTimeout(positionManager.balanceOf(address),7000,'Uniswap V3 position count')));if(!count)return[];const factory=new ethers.Contract(UNISWAP_V3_FACTORY,['function getPool(address tokenA,address tokenB,uint24 fee) view returns (address pool)'],provider);const assets=[];for(let index=0;index<count;index+=1){try{const tokenId=await withTimeout(positionManager.tokenOfOwnerByIndex(address,index),7000,'Uniswap V3 token ID');const position=await withTimeout(positionManager.positions(tokenId),7000,'Uniswap V3 position');const token0=String(position.token0??position[2]);const token1=String(position.token1??position[3]);const fee=Number(position.fee??position[4]);const liquidity=BigInt((position.liquidity??position[7]).toString());if(liquidity===0n)continue;const poolAddress=await withTimeout(factory.getPool(token0,token1,fee),7000,'Uniswap V3 pool');if(poolAddress===ethers.constants.AddressZero)continue;const pool=new ethers.Contract(poolAddress,['function slot0() view returns (uint160 sqrtPriceX96,int24 tick,uint16 observationIndex,uint16 observationCardinality,uint16 observationCardinalityNext,uint8 feeProtocol,bool unlocked)'],provider);const [slot0,info0,info1]=await Promise.all([withTimeout(pool.slot0(),7000,'Uniswap V3 pool state'),lpTokenInfo(provider,token0),lpTokenInfo(provider,token1)]);const tickLower=Number(position.tickLower??position[5]);const tickUpper=Number(position.tickUpper??position[6]);const currentTick=Number(slot0.tick??slot0[1]);const principal=amountsForLiquidity(BigInt((slot0.sqrtPriceX96??slot0[0]).toString()),sqrtRatioAtTick(tickLower),sqrtRatioAtTick(tickUpper),liquidity);let fee0=BigInt((position.tokensOwed0??position[10]).toString());let fee1=BigInt((position.tokensOwed1??position[11]).toString());try{const collected=await withTimeout(positionManager.callStatic.collect({tokenId,recipient:address,amount0Max:MAX_UINT128,amount1Max:MAX_UINT128},{from:address}),7000,'Collectable V3 fees');fee0=BigInt((collected.amount0??collected[0]).toString());fee1=BigInt((collected.amount1??collected[1]).toString())}catch{}const amount0=Number(ethers.utils.formatUnits(principal.amount0.toString(),info0.decimals));const amount1=Number(ethers.utils.formatUnits(principal.amount1.toString(),info1.decimals));const fees0=Number(ethers.utils.formatUnits(fee0.toString(),info0.decimals));const fees1=Number(ethers.utils.formatUnits(fee1.toString(),info1.decimals));const priced=info0.price>0&&info1.price>0;const value=priced?(amount0+fees0)*info0.price+(amount1+fees1)*info1.price:0;assets.push({chain:'ethereum',address:UNISWAP_V3_POSITION_MANAGER,name:`${info0.symbol}/${info1.symbol} Uniswap V3 LP`,symbol:`${info0.symbol}/${info1.symbol}`,amount:1,value,type:'LP Token',tokenType:'Uniswap V3',tokenId:tokenId.toString(),positionTokenId:tokenId.toString(),icon:null,reputation:'ok',priced,lp:{version:'V3',token0:info0.symbol,token1:info1.symbol,amount0,amount1,fee0:fees0,fee1:fees1,feeTier:fee/10000,tickLower,tickUpper,currentTick,inRange:currentTick>=tickLower&&currentTick<tickUpper}})}catch(error){console.warn(`Uniswap V3 position ${index} unavailable for ${address}`,error)}}return assets}
async function enrichV2LpAssets(provider,assets){return Promise.all(assets.map(async asset=>{if(asset.type!=='LP Token'||asset.tokenType!=='ERC-20'||!ethers.utils.isAddress(asset.address||''))return asset;try{const pair=new ethers.Contract(asset.address,['function token0() view returns (address)','function token1() view returns (address)','function getReserves() view returns (uint112 reserve0,uint112 reserve1,uint32 blockTimestampLast)','function totalSupply() view returns (uint256)'],provider);const [token0,token1,reserves,totalSupply]=await Promise.all([withTimeout(pair.token0(),7000,'V2 LP token0'),withTimeout(pair.token1(),7000,'V2 LP token1'),withTimeout(pair.getReserves(),7000,'V2 LP reserves'),withTimeout(pair.totalSupply(),7000,'V2 LP supply')]);const [info0,info1]=await Promise.all([lpTokenInfo(provider,token0,asset.chain),lpTokenInfo(provider,token1,asset.chain)]);const supply=Number(ethers.utils.formatUnits(totalSupply,Number(asset.decimals||18)));if(!(supply>0))return asset;const share=asset.amount/supply;const amount0=Number(ethers.utils.formatUnits(reserves.reserve0??reserves[0],info0.decimals))*share;const amount1=Number(ethers.utils.formatUnits(reserves.reserve1??reserves[1],info1.decimals))*share;const priced=info0.price>0&&info1.price>0;return{...asset,name:`${info0.symbol}/${info1.symbol} V2 LP`,symbol:`${info0.symbol}/${info1.symbol}`,value:priced?amount0*info0.price+amount1*info1.price:0,priced,lp:{version:'V2',token0:info0.symbol,token1:info1.symbol,amount0,amount1,fee0:0,fee1:0,feesEmbedded:true,share}}}catch(error){console.warn(`V2 LP valuation unavailable for ${asset.address}`,error);return asset}}))}
async function fetchLegacyRvltAsset(provider,address){const token=new ethers.Contract(LEGACY_RVLT_REF.split(':')[1],['function balanceOf(address) view returns (uint256)'],provider);const raw=await withTimeout(token.balanceOf(address),7000,'Legacy RVLT balance');const amount=Number(ethers.utils.formatUnits(raw,18));if(!(amount>0))return null;const priced=state.legacyRvltUnitPrice>0;return {chain:'polygon',address:LEGACY_RVLT_REF.split(':')[1],name:'Revolt 2 Earn (Legacy)',symbol:'RVLT',amount,value:priced?amount*state.legacyRvltUnitPrice:0,type:'Token',tokenType:'ERC-20',tokenId:null,icon:null,reputation:'ok',priced}}
async function fetchDcultState(provider,address){
  const urls=CHAINS.ethereum.rpc;
  const candidates=[provider,...urls.filter(url=>provider?.connection?.url!==url).map(url=>new ethers.providers.StaticJsonRpcProvider(url,{chainId:1,name:'homestead'}))];
  let raw,delegatee,isGuardian,lastError;
  for(const candidate of candidates){
    try{
      const token=new ethers.Contract(DCULT_TOKEN_ADDRESS,[
        'function balanceOf(address) view returns (uint256)',
        'function delegates(address) view returns (address)',
        'function checkHighestStaker(uint256,address) view returns (bool)'
      ],candidate);
      [raw,delegatee,isGuardian]=await withTimeout(Promise.all([
        token.balanceOf(address),
        token.delegates(address),
        token.checkHighestStaker(0,address).catch(()=>false)
      ]),7000,'dCULT voting readiness');
      break;
    }catch(error){lastError=error}
  }
  if(raw===undefined||delegatee===undefined)throw lastError||new Error('No Ethereum RPC returned dCULT voting readiness');
  const delegation=CultDelegationStatus.classify({address,balance:raw.toString(),delegatee,isGuardian});
  const amount=Number(ethers.utils.formatUnits(raw,18));
  if(!(amount>0))return {asset:null,delegation:{...delegation,balance:raw.toString()}};
  const cultRate=unitPrice('cult-dao');
  const priced=cultRate>0;
  const asset={chain:'ethereum',address:DCULT_TOKEN_ADDRESS,name:'dCULT - Staked CULT',symbol:'dCULT',amount,value:priced?amount*cultRate:0,type:'Token',tokenType:'ERC-20',tokenId:null,icon:null,reputation:'ok',priced};
  return {asset,delegation:{...delegation,balance:raw.toString()}};
}
async function refreshCurrentErc20Balances(provider,walletAddress,assets){return (await Promise.all(assets.map(async asset=>{if(asset.tokenType!=='ERC-20'||!ethers.utils.isAddress(asset.address||''))return asset;try{const token=new ethers.Contract(asset.address,['function balanceOf(address) view returns (uint256)'],provider);const raw=await withTimeout(token.balanceOf(walletAddress),7000,`${asset.symbol||'Token'} current balance`);const amount=Number(ethers.utils.formatUnits(raw,Number(asset.decimals||0)));if(!(amount>0))return null;const rate=asset.amount>0?(asset.value||0)/asset.amount:0;return {...asset,amount,value:amount*rate}}catch(error){console.warn(`Current ${asset.symbol||'token'} balance unavailable for ${walletAddress}; keeping indexed balance`,error);return asset}}))).filter(Boolean)}
function saveManualTokens(){localStorage.setItem('cultFundsManualTokens',JSON.stringify(manualTokens))}
async function scanManualTokenOnChain(chain,address,{remember=true}={}){const provider=await providerFor(chain);const checksum=ethers.utils.getAddress(address);const code=await withTimeout(provider.getCode(checksum),7000,`${chain} token contract`);if(!code||code==='0x')throw new Error(`No contract on ${CHAINS[chain].name}`);const contract=new ethers.Contract(checksum,['function name() view returns (string)','function symbol() view returns (string)','function decimals() view returns (uint8)','function balanceOf(address) view returns (uint256)'],provider);const decimals=Number(await withTimeout(contract.decimals(),7000,`${chain} token decimals`));if(!Number.isFinite(decimals)||decimals<0||decimals>36)throw new Error(`Unsupported token decimals on ${CHAINS[chain].name}`);const [name,symbol]=await Promise.all([withTimeout(contract.name(),7000,`${chain} token name`).catch(()=>short(checksum)),withTimeout(contract.symbol(),7000,`${chain} token symbol`).catch(()=>short(checksum))]);const balances=await Promise.all(state.wallets.map(async wallet=>{try{const raw=await withTimeout(contract.balanceOf(wallet.address),7000,`${chain} token balance`);return {wallet,amount:Number(ethers.utils.formatUnits(raw,decimals))}}catch{return {wallet,amount:0}}}));let holders=0;let total=0;balances.forEach(({wallet,amount})=>{if(!(amount>0))return;holders+=1;total+=amount;const key=`${wallet.address}:${chain}`;const row=state.data.get(key)||{chain,assets:[],safe:null,error:null};const ref=`${chain}:${checksum.toLowerCase()}`;if(!row.assets.some(asset=>assetKey(asset)===ref))row.assets.push({chain,address:checksum,name:String(name||symbol||short(checksum)),symbol:String(symbol||name||short(checksum)),amount,value:0,type:'Token',tokenType:'ERC-20',tokenId:null,icon:null,reputation:'manual',priced:false});state.data.set(key,row)});if(remember&&!manualTokens.some(token=>token.chain===chain&&token.address.toLowerCase()===checksum.toLowerCase())){manualTokens.push({chain,address:checksum});saveManualTokens()}render();return {chain,address:checksum,name:String(name||symbol||short(checksum)),symbol:String(symbol||name||short(checksum)),holders,total}}
async function scanSavedManualTokens(){for(const token of manualTokens){try{await scanManualTokenOnChain(token.chain,token.address,{remember:false})}catch(error){console.warn(`Manual token scan failed for ${token.chain}:${token.address}`,error)}}}
async function checkManualTokenAddress(){const input=document.querySelector('#manual-token-address');const button=document.querySelector('#manual-token-scan');const address=input.value.trim();if(!ethers.utils.isAddress(address))return toast('Enter a valid token contract');const chains=state.chain==='all'?Object.keys(CHAINS):[state.chain];button.disabled=true;button.textContent='Checking…';const results=await Promise.all(chains.map(chain=>scanManualTokenOnChain(chain,address).catch(error=>({chain,error}))));const found=results.filter(result=>!result.error);const holders=found.reduce((sum,result)=>sum+result.holders,0);if(!found.length)toast('Token contract not found on selected network');else if(!holders)toast(`Token saved · no tracked balances found`);else toast(`${found[0].symbol} found in ${holders} tracked wallet${holders===1?'':'s'}`);button.disabled=false;button.textContent='Check token'}
function renderManualTokenScope(){const scope=document.querySelector('#manual-token-scope');const button=document.querySelector('#manual-token-scan');const label=state.chain==='all'?'All networks':CHAINS[state.chain].name;if(scope)scope.textContent=label;if(button)button.title=`Check this token contract on ${label}`}
function classifyIndexedToken(token){const type=token.type||'Token';if(type==='ERC-721'||type==='ERC-1155')return 'NFT';const text=`${token.name||''} ${token.symbol||''}`.toLowerCase();if(/\b(lp|liquidity|uniswap|sushiswap|curve|balancer)\b/.test(text))return 'LP Token';return 'Token'}
const SAFE_SERVICE_SLUGS={ethereum:'eth',base:'base',polygon:'pol'};
const ENABLE_SAFE_TRANSACTION_STATUS=false;
const SAFE_STATUS_TIMEOUT_MS=4000;
const SAFE_STATUS_COOLDOWN_MS=5*60*1000;
const safeServiceCooldownUntil=new Map;
const safeStatusQueues=new Map;
async function fetchSafeService(chain,url){if((safeServiceCooldownUntil.get(chain)||0)>Date.now())return null;const controller=new AbortController;const timeout=setTimeout(()=>controller.abort(),SAFE_STATUS_TIMEOUT_MS);try{const response=await fetch(url,{signal:controller.signal});if(response.status===429){const retryAfter=Number(response.headers.get('retry-after'));safeServiceCooldownUntil.set(chain,Date.now()+(Number.isFinite(retryAfter)&&retryAfter>0?retryAfter*1000:SAFE_STATUS_COOLDOWN_MS));return null}return response}catch{return null}finally{clearTimeout(timeout)}}
function queueSafePending(chain,address,threshold){const previous=safeStatusQueues.get(chain)||Promise.resolve();const next=previous.catch(()=>null).then(()=>fetchSafePending(chain,address,threshold));safeStatusQueues.set(chain,next.catch(()=>null));return next}
async function fetchLatestChainAction(chain,address){const response=await fetchWithRetry(`${CHAINS[chain].indexer}/api/v2/addresses/${address}/transactions`);if(!response.ok)return null;const payload=await response.json();const transaction=payload.items?.[0];if(!transaction)return null;return {txHash:transaction.hash||null,safeTxHash:null,date:transaction.timestamp||null,nonce:transaction.nonce??null,chain}}
async function fetchSafePending(chain,address,threshold){const slug=SAFE_SERVICE_SLUGS[chain];if(!slug)return null;const base=`https://api.safe.global/tx-service/${slug}/api/v1/safes/${address}/multisig-transactions/`;const [response,chainLatest]=await Promise.all([fetchSafeService(chain,`${base}?executed=false&trusted=true&limit=50`),fetchLatestChainAction(chain,address).catch(()=>null)]);if(!response?.ok)return chainLatest?{count:0,ready:0,waiting:0,items:[],latest:chainLatest}:null;const payload=await response.json();const transactions=(payload.results||[]).filter(transaction=>!transaction.isExecuted&&transaction.trusted!==false&&transaction.isTrusted!==false);const items=transactions.map(transaction=>{const confirmations=transaction.confirmations?.length||0;const required=Number(transaction.confirmationsRequired||threshold||0);return {safeTxHash:transaction.safeTxHash,nonce:transaction.nonce,confirmations,required,missing:Math.max(0,required-confirmations),ready:required>0&&confirmations>=required}});return {count:items.length,ready:items.filter(item=>item.ready).length,waiting:items.filter(item=>!item.ready).length,items,latest:items.length?null:chainLatest}}
async function discoverAssets(chain,address){const response=await fetchWithRetry(`${CHAINS[chain].indexer}/api/v2/addresses/${address}/token-balances`,{},1,8000);if(!response.ok)throw new Error(`${CHAINS[chain].name} asset index unavailable`);const balances=await response.json();const fx=fiatRate();return balances.map(item=>{const token=item.token||{};const tokenType=token.type||'ERC-20';const isNft=tokenType==='ERC-721'||tokenType==='ERC-1155';const decimals=isNft?0:Number(token.decimals||0);const amount=isNft?Number(item.value||0):Number(ethers.utils.formatUnits(item.value||'0',decimals));const assetRef=`${chain}:${String(token.address_hash||'').toLowerCase()}`;const indexedUsd=Number(token.exchange_rate||0);const fallbackId=TRUSTED_PRICE_IDS[assetRef];const selectedRate=assetRef===DCULT_REF?unitPrice('cult-dao'):assetRef===ENA_REF&&state.enaUnitPrice>0?state.enaUnitPrice:assetRef===LEGACY_RVLT_REF?state.legacyRvltUnitPrice:(indexedUsd>0?indexedUsd*fx:(fallbackId?unitPrice(fallbackId):0));return {chain,address:token.address_hash,name:assetRef===DCULT_REF?'dCULT - Staked CULT':token.name||token.symbol||short(token.address_hash||''),symbol:assetRef===DCULT_REF?'dCULT':token.symbol||token.name||'Unknown',amount,value:isNft?0:amount*selectedRate,type:classifyIndexedToken(token),tokenType,decimals,tokenId:item.token_id??null,icon:token.icon_url||null,reputation:token.reputation||'unknown',priced:selectedRate>0}}).filter(asset=>asset.amount>0&&!hiddenAssets.has(assetKey(asset))&&(isTrustedAsset(asset)||asset.type==='LP Token'||(asset.type==='NFT'?state.showNfts:(asset.priced||state.showUnpriced))))}
async function scanChain(chain){
  const p=await providerFor(chain);
  for(const w of state.wallets){
    const key=`${w.address}:${chain}`;
    const row={chain,assets:[],safe:null,error:null};
    const [code,native,indexedAssets,legacyRvlt,dcultState]=await Promise.all([
      withTimeout(p.getCode(w.address),7000,`${chain} contract code`).catch(()=>null),
      withTimeout(p.getBalance(w.address),7000,`${chain} native balance`).catch(()=>null),
      discoverAssets(chain,w.address).catch(error=>{row.error=error.message;return[]}),
      chain==='polygon'?fetchLegacyRvltAsset(p,w.address).catch(error=>{console.warn(`Legacy RVLT balance unavailable for ${w.address}`,error);return null}):Promise.resolve(null),
      chain==='ethereum'?fetchDcultState(p,w.address).catch(error=>{console.warn(`dCULT voting readiness unavailable for ${w.address}`,error);return null}):Promise.resolve(null)
    ]);
    let discovered=await refreshCurrentErc20Balances(p,w.address,indexedAssets);
    discovered=await enrichV2LpAssets(p,discovered);
    if(native){
      const nativeAmount=Number(ethers.utils.formatEther(native));
      if(nativeAmount>0)row.assets.push({chain,symbol:CHAINS[chain].native,name:CHAINS[chain].native,amount:nativeAmount,value:nativeAmount*unitPrice(CHAINS[chain].price),type:'Native',priced:true});
    }
    row.assets.push(...discovered);
    if(legacyRvlt&&!hiddenAssets.has(LEGACY_RVLT_REF)&&!row.assets.some(asset=>assetKey(asset)===LEGACY_RVLT_REF))row.assets.push(legacyRvlt);
    if(dcultState?.delegation)row.delegation=dcultState.delegation;
    if(dcultState?.asset&&!hiddenAssets.has(DCULT_REF)&&!row.assets.some(asset=>assetKey(asset)===DCULT_REF))row.assets.push(dcultState.asset);
    if(chain==='ethereum'){
      const positions=await fetchV3LpAssets(p,w.address).catch(error=>{console.warn(`Uniswap V3 position scan unavailable for ${w.address}`,error);return[]});
      row.assets.push(...positions.filter(asset=>!hiddenAssets.has(assetKey(asset))));
    }
    state.data.set(key,row);
    render();
    if(code&&code!=='0x'){
      try{
        const s=new ethers.Contract(w.address,SAFE_ABI,p);
        const [owners,thresholdRaw]=await Promise.all([withTimeout(s.getOwners(),7000,'Safe owners'),withTimeout(s.getThreshold(),7000,'Safe threshold')]);
        const threshold=Number(thresholdRaw);
        row.safe={owners,threshold,pending:null};
        render();
        if(ENABLE_SAFE_TRANSACTION_STATUS)queueSafePending(chain,w.address,threshold).then(pending=>{row.safe.pending=pending;render()}).catch(()=>{});
      }catch{}
    }
    await wait(120);
  }
}
async function refresh(options={}){const skipPrices=options?.skipPrices===true;document.querySelector('#status').textContent=state.data.size?'Cached data shown · updating…':'Scanning balances and contracts…';document.querySelector('#refresh').disabled=true;try{if(!skipPrices)await fetchPrices();fetchTreasuryCultValue().catch(error=>console.warn('Treasury CULT value unavailable',error));await Promise.all([fetchLegacyRvltPrice(),fetchEnaPoolPrice()]);await Promise.all(Object.keys(CHAINS).map(scanChain));await scanSavedManualTokens();saveActivePortfolioCache();document.querySelector('#status').textContent=`Updated ${new Date().toLocaleTimeString()}`}catch(e){document.querySelector('#status').textContent=e.message}finally{document.querySelector('#refresh').disabled=false;render()}}
