function lpDetailsMarkup(asset){const lp=asset.lp;if(!lp)return'';const amount=value=>Number(value||0).toLocaleString(undefined,{maximumFractionDigits:6});const principal=`${amount(lp.amount0)} ${escapeHtml(lp.token0)} + ${amount(lp.amount1)} ${escapeHtml(lp.token1)}`;const fees=lp.version==='V3'?` · Fees ${amount(lp.fee0)} ${escapeHtml(lp.token0)} + ${amount(lp.fee1)} ${escapeHtml(lp.token1)}`:' · Fees included in reserves';const range=lp.version==='V3'?` · ${lp.inRange?'In range':'Out of range'} · ${Number(lp.feeTier||0).toFixed(2)}% fee`:'';return `<small class="lp-position-details">Position #${escapeHtml(String(asset.positionTokenId||asset.tokenId||''))} · ${principal}${fees}${range}</small>`}
function decorateLpDetails(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);if(!wallet)return;const assets=walletRows(wallet).flatMap(row=>row.assets||[]).filter(asset=>state.chain==='all'||asset.chain===state.chain).filter(asset=>asset.value>=state.threshold||!asset.priced).sort((a,b)=>b.value-a.value);const rows=[...card.querySelectorAll('.assets .asset-data-row')];assets.forEach((asset,index)=>{if(!asset.lp)return;const identity=rows[index]?.firstElementChild;if(!identity||identity.querySelector('.lp-position-details'))return;identity.querySelector('small')?.insertAdjacentHTML('afterend',lpDetailsMarkup(asset))})})}
function render(){const box=document.querySelector('#wallets');box.innerHTML='';let grand=0,assetCount=0,safes=new Map();for(const w of state.wallets){const rows=walletRows(w);const detectedSafes=rows.filter(r=>r.safe).map(r=>r.safe);window.CultWalletStructuralState?.primeSafe?.(w.address,detectedSafes);const assets=rows.flatMap(r=>r.assets||[]).filter(a=>state.chain==='all'||a.chain===state.chain);const value=assets.reduce((s,a)=>s+a.value,0);grand+=value;assetCount+=assets.filter(a=>a.value>0).length;rows.forEach(r=>{if(r.safe)safes.set(w.address,r.safe)});const hay=`${w.address} ${w.label} ${w.note} ${assets.map(a=>`${a.symbol} ${a.name} ${assetDisplayName(a)}`).join(' ')}`.toLowerCase();if(state.query&&!hay.includes(state.query))continue;const card=document.createElement('article');card.className='wallet-card';const networkSummary=window.CultNetworkSummary?.summarize(rows.filter(r=>r.assets?.length||r.safe).map(r=>CHAINS[r.chain]?.name))||null;const badges=networkSummary?`<span class="pill network-summary" tabindex="0" data-network-tooltip="${escapeAttr(networkSummary.tooltip)}" aria-label="${escapeAttr(`${networkSummary.label}. ${networkSummary.tooltip}`)}">${escapeHtml(networkSummary.label)}</span>`:'';const safe=detectedSafes[0];card.innerHTML=`<div class="wallet-head"><div class="wallet-title"><div><h3>${escapeHtml(w.label||short(w.address))}${MANAGERS.has(w.address.toLowerCase())?' · LP':''}</h3><a class="address" target="_blank" rel="noopener" href="${CHAINS[state.chain==='all'?'ethereum':state.chain].explorer}${w.address}">${short(w.address)}</a>${w.note?`<p class="note">${escapeHtml(w.note)}</p>`:''}</div></div><div class="chain-pills">${safe?`<span class="pill safe">Safe ${safe.threshold}/${safe.owners.length}</span>`:''}${badges}</div><div class="wallet-value">${money(value)}</div><div class="actions"><button data-copy title="Copy address">⧉</button><button data-edit title="Edit local label">✎</button></div></div><div class="assets">${assets.filter(a=>a.value>=state.threshold||!a.priced).sort((a,b)=>b.value-a.value).map((a,index)=>`<div class="asset-row asset-data-row"><span><strong>${escapeHtml(assetDisplayName(a))}</strong> <small>${escapeHtml(a.symbol)} · ${a.type} · ${CHAINS[a.chain].name}</small> <button class="asset-rename" data-asset-index="${index}" title="Set local token name">✎</button></span><span class="asset-unit-price" title="Unit price">${assetUnitPrice(a)}</span><span class="asset-amount" title="${escapeAttr(a.amount.toLocaleString(undefined,{maximumFractionDigits:12}))} ${escapeAttr(a.symbol)}">${assetAmountDisplay(a.amount)}</span><span class="asset-total-value">${a.priced?money(a.value):'Unpriced'}</span></div>`).join('')||'<div class="empty">No discovered balances found above the current threshold.</div>'}${safe?`<div class="asset-row"><span>Safe owners · threshold ${safe.threshold}</span><span></span><span>${safe.owners.map(a=>`<a class="address" href="${CHAINS.ethereum.explorer}${a}" target="_blank">${short(a)}</a>`).join(' ')}</span></div>`:''}</div><div class="edit-fields"><input data-label value="${escapeAttr(w.label)}" placeholder="Local label"><input data-note value="${escapeAttr(w.note)}" placeholder="Short local description"><button data-save>Save</button></div>`;card.querySelector('[data-copy]').onclick=()=>navigator.clipboard.writeText(w.address).then(()=>toast('Address copied'));card.querySelector('[data-edit]').onclick=()=>card.classList.toggle('editing');card.querySelector('[data-save]').onclick=()=>{w.label=card.querySelector('[data-label]').value.trim();w.note=card.querySelector('[data-note]').value.trim();save();render();toast('Local label saved')};card.querySelectorAll('[data-asset-index]').forEach(button=>button.onclick=()=>renameAsset(assets[Number(button.dataset.assetIndex)]));box.append(card)}document.querySelector('#total-value').textContent=money(grand);document.querySelector('#priced-assets').textContent=assetCount;document.querySelector('#safe-count').textContent=assetCount;document.querySelector('#safe-count').textContent=safes.size;document.querySelector('#safe-meta').textContent=safes.size?'Owners shown per wallet':'No Safes detected yet';document.querySelector('#total-meta').textContent=`${state.wallets.length} wallets · 3 networks`}
function escapeHtml(s=''){return s.replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]))}function escapeAttr(s=''){return escapeHtml(s)}
function compactLinkLabel(value){try{const parsed=new URL(value);const host=parsed.hostname.replace(/^www\./,'');const path=parsed.pathname==='/'?'':parsed.pathname.replace(/\/$/,'');const label=`${host}${path}`;return label.length>36?`${label.slice(0,33)}…`:label}catch{return value.length>36?`${value.slice(0,33)}…`:value}}
function linkifyText(value=''){const text=String(value);const pattern=/https?:\/\/[^\s<>"']+/gi;let html='';let last=0;text.replace(pattern,(match,offset)=>{let url=match;let trailing='';while(/[),.;!?]$/.test(url)){trailing=url.slice(-1)+trailing;url=url.slice(0,-1)}html+=escapeHtml(text.slice(last,offset));html+=`<a href="${escapeAttr(url)}" title="${escapeAttr(url)}" target="_blank" rel="noopener noreferrer">${escapeHtml(compactLinkLabel(url))}</a>${escapeHtml(trailing)}`;last=offset+match.length;return match});return html+escapeHtml(text.slice(last))}
