async function addWalletEntries(raw) {
  const entries = raw.split(/[;,\n]+/).map(value => value.trim()).filter(Boolean);
  if (!entries.length) return toast('Enter a wallet address or ENS name');
  const ethereumProvider = await providerFor('ethereum').catch(() => null);
  let added = 0;
  for (const entry of entries) {
    let address = entry;
    if (entry.toLowerCase().endsWith('.eth') && ethereumProvider) address = await ethereumProvider.resolveName(entry);
    if (!address || !ethers.utils.isAddress(address)) { toast(`Could not add ${entry}`); continue; }
    address = ethers.utils.getAddress(address);
    if (state.wallets.some(wallet => wallet.address.toLowerCase() === address.toLowerCase())) continue;
    state.wallets.push({ address, label: entry.toLowerCase().endsWith('.eth') ? entry : '', note: '' });
    added += 1;
  }
  if (!added) return toast('No new wallets to add');
  save();
  document.querySelector('#track-wallet-input').value = '';
  toast(`${added} wallet${added === 1 ? '' : 's'} added`);
  await refresh();
}

document.querySelector('#track-wallet-button').onclick = () => addWalletEntries(document.querySelector('#track-wallet-input').value);
document.querySelector('#track-wallet-input').onkeydown = event => {
  if (event.key === 'Enter') { event.preventDefault(); addWalletEntries(event.currentTarget.value); }
};
