function renderPortfolioOverview(){const assets=[...state.data.entries()].flatMap(([key,row])=>(row.assets||[]).map(asset=>({...asset,owner:key.slice(0,key.lastIndexOf(':'))})));const totalFor=predicate=>assets.filter(predicate).reduce((sum,asset)=>sum+(asset.value||0),0);const set=(id,value)=>{const node=document.getElementById(id);if(node)node.textContent=value};Object.keys(CHAINS).forEach(chain=>set(`overview-${chain}`,money(totalFor(asset=>asset.chain===chain))));set('overview-native',money(totalFor(asset=>asset.type==='Native')));set('overview-tokens',money(totalFor(asset=>asset.type==='Token')));set('overview-lp',money(totalFor(asset=>asset.type==='LP Token')));set('overview-assets',assets.length.toLocaleString());set('overview-unpriced',assets.filter(asset=>asset.type==='LP Token'&&!asset.priced).length.toLocaleString());const grouped=new Map;assets.forEach(asset=>{const key=assetKey(asset);const current=grouped.get(key)||{...asset,amount:0,value:0,wallets:new Set,holderAmounts:new Map};current.amount+=asset.amount||0;current.value+=asset.value||0;current.wallets.add(asset.owner);current.holderAmounts.set(asset.owner,(current.holderAmounts.get(asset.owner)||0)+(asset.amount||0));current.priced=current.priced||asset.priced;grouped.set(key,current)});const list=document.getElementById('overview-asset-list');if(!list)return;const rows=[...grouped.values()].sort((a,b)=>(b.priced-a.priced)||(b.value-a.value)||assetDisplayName(a).localeCompare(assetDisplayName(b)));list.innerHTML=rows.map(asset=>{const holders=[...asset.wallets].map(address=>{const wallet=state.wallets.find(item=>item.address.toLowerCase()===address.toLowerCase());const label=wallet?.label||short(address);const holderAmount=(asset.holderAmounts.get(address)||0).toLocaleString(undefined,{maximumFractionDigits:8});const tooltip=`${address}\n${holderAmount} ${asset.symbol}`;return `<a href="${CHAINS[asset.chain].explorer}${address}" target="_blank" rel="noopener noreferrer" title="${escapeAttr(tooltip)}">${escapeHtml(label)}</a>`}).join('<span class="holder-separator"> | </span>');return `<div class="overview-asset-row"><span class="asset-identity"><strong>${escapeHtml(assetDisplayName(asset))}</strong><small>${escapeHtml(asset.symbol)} · ${CHAINS[asset.chain].name} · ${asset.type}</small><span class="asset-holders"><small>${asset.wallets.size} wallet${asset.wallets.size===1?'':'s'}</small>${holders}</span></span><span class="asset-unit-price" title="Unit price">${assetUnitPrice(asset)}</span><span class="asset-amount">${asset.amount.toLocaleString(undefined,{maximumFractionDigits:6})}</span><span class="asset-total-value">${asset.priced?money(asset.value):'Unpriced'}</span></div>`}).join('')||'<p class="empty">No visible assets found.</p>'}
function walletFromCard(card){const href=card.querySelector('.wallet-title .address')?.href||'';const address=href.split('/').filter(Boolean).pop();return state.wallets.find(wallet=>wallet.address.toLowerCase()===String(address).toLowerCase())}
function decorateAssetIcons(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);if(!wallet)return;const assets=walletRows(wallet).flatMap(row=>row.assets||[]).filter(asset=>state.chain==='all'||asset.chain===state.chain).filter(asset=>asset.value>=state.threshold||!asset.priced).sort((a,b)=>b.value-a.value);const rows=[...card.querySelectorAll('.assets .asset-row')];assets.forEach((asset,index)=>{const identity=rows[index]?.querySelector(':scope > span:first-child');if(!identity||identity.querySelector('.token-icon'))return;identity.classList.add('asset-primary');identity.prepend(createAssetIcon(asset))})});const grouped=new Map;state.data.forEach(row=>(row.assets||[]).forEach(asset=>{const key=assetKey(asset);const current=grouped.get(key)||{...asset,value:0,priced:false};current.value+=asset.value||0;current.priced=current.priced||asset.priced;grouped.set(key,current)}));const assets=[...grouped.values()].sort((a,b)=>(b.priced-a.priced)||(b.value-a.value)||assetDisplayName(a).localeCompare(assetDisplayName(b)));const rows=[...document.querySelectorAll('#overview-asset-list .overview-asset-row')];assets.forEach((asset,index)=>{const identity=rows[index]?.querySelector('.asset-identity');if(!identity||identity.querySelector('.token-icon'))return;identity.prepend(createAssetIcon(asset))})}
function decorateHeroTotal(){const value=state.wallets.flatMap(wallet=>walletRows(wallet)).flatMap(row=>row.assets||[]).filter(asset=>state.chain==='all'||asset.chain===state.chain).reduce((sum,asset)=>sum+(asset.value||0),0);const total=document.querySelector('#total-value');if(total){total.innerHTML=heroValueMarkup(value);const length=total.textContent.replace(/\s/g,'').length;total.dataset.numberSize=length<=10?'short':length>=16?'long':'standard';total.title=money(value)}}
function decorateAssetAmounts(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);if(!wallet)return;const assets=walletRows(wallet).flatMap(row=>row.assets||[]).filter(asset=>state.chain==='all'||asset.chain===state.chain).filter(asset=>asset.value>=state.threshold||!asset.priced).sort((a,b)=>b.value-a.value);const rows=[...card.querySelectorAll('.assets .asset-data-row')];assets.forEach((asset,index)=>{const amount=rows[index]?.querySelector('.asset-amount');if(!amount)return;amount.innerHTML=assetAmountDisplay(asset);amount.title=`${asset.amount.toLocaleString(undefined,{maximumFractionDigits:12})} ${asset.symbol}`})});const grouped=new Map;state.data.forEach(row=>(row.assets||[]).forEach(asset=>{const key=assetKey(asset);const current=grouped.get(key)||{...asset,amount:0,value:0,priced:false};current.amount+=asset.amount||0;current.value+=asset.value||0;current.priced=current.priced||asset.priced;grouped.set(key,current)}));const assets=[...grouped.values()].sort((a,b)=>(b.priced-a.priced)||(b.value-a.value)||assetDisplayName(a).localeCompare(assetDisplayName(b)));const rows=[...document.querySelectorAll('#overview-asset-list .overview-asset-row')];assets.forEach((asset,index)=>{const amount=rows[index]?.querySelector('.asset-amount');if(!amount)return;amount.innerHTML=assetAmountDisplay(asset);amount.title=`${asset.amount.toLocaleString(undefined,{maximumFractionDigits:12})} ${asset.symbol}`})}
function applyOverviewAssetThreshold(){const threshold=assetOverviewThreshold();const grouped=new Map;state.data.forEach(row=>(row.assets||[]).forEach(asset=>{const key=assetKey(asset);const current=grouped.get(key)||{...asset,value:0,priced:false};current.value+=asset.value||0;current.priced=current.priced||asset.priced;grouped.set(key,current)}));const assets=[...grouped.values()].sort((a,b)=>(b.priced-a.priced)||(b.value-a.value)||assetDisplayName(a).localeCompare(assetDisplayName(b)));const rows=[...document.querySelectorAll('#overview-asset-list .overview-asset-row')];let shown=0;assets.forEach((asset,index)=>{const hidden=asset.priced&&asset.value<threshold;if(rows[index])rows[index].hidden=hidden;if(!hidden)shown+=1});const label=document.querySelector('#asset-threshold-label');const count=document.querySelector('#asset-threshold-count');if(label)label.textContent=money(threshold);if(count)count.textContent=`${shown} shown`}
function applyWalletAssetThreshold(){const threshold=assetOverviewThreshold();document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);const container=card.querySelector('.assets');if(!wallet||!container)return;const assets=walletRows(wallet).flatMap(row=>row.assets||[]).filter(asset=>state.chain==='all'||asset.chain===state.chain).sort((a,b)=>b.value-a.value);const rows=[...container.querySelectorAll('.asset-row')];let shown=0;assets.forEach((asset,index)=>{const hidden=asset.priced&&asset.value<threshold;if(rows[index])rows[index].hidden=hidden;if(!hidden)shown+=1});let summary=container.querySelector('.wallet-asset-count');if(!summary){summary=document.createElement('div');summary.className='wallet-asset-count';container.prepend(summary)}summary.textContent=`${shown} / ${assets.length} assets`});const count=document.querySelector('#wallet-threshold-count');if(count)count.textContent=`${count.textContent} · assets ≥ ${money(threshold)}`}
function decorateWalletAnchors(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);if(wallet)card.id=walletAnchor(wallet.address)});document.querySelectorAll('#overview-asset-list .asset-holders a').forEach(link=>{const address=link.href.split('/').filter(Boolean).pop();if(!ethers.utils.isAddress(address))return;const target=walletAnchor(address);link.href=`#${target}`;link.dataset.walletAnchor=target;link.removeAttribute('target');link.removeAttribute('rel');link.title=`${link.title}\nShow wallet overview`})}
function renderPortfolioDonut(){
  const donut=document.getElementById('portfolio-donut');
  const label=document.getElementById('portfolio-donut-label');
  const tooltip=document.getElementById('portfolio-donut-tooltip');
  if(!donut||!label)return;
  document.querySelectorAll('[data-donut-mode]').forEach(button=>{const active=button.dataset.donutMode===portfolioDonutMode;button.classList.toggle('active',active);button.setAttribute('aria-pressed',String(active))});
  let entries=[];
  if(portfolioDonutMode==='wallets')entries=state.wallets.map(wallet=>{const rows=walletRows(wallet);const value=rows.flatMap(row=>row.assets||[]).reduce((sum,asset)=>sum+(asset.value||0),0);const safe=rows.find(row=>row.safe)?.safe;return{name:wallet.label||short(wallet.address),value,address:wallet.address,safeLabel:safe?`Safe ${safe.threshold}/${safe.owners.length}`:''}}).filter(item=>item.value>0);
  else{const grouped=new Map;state.data.forEach(row=>(row.assets||[]).forEach(asset=>{if((asset.value||0)<=0)return;const name=assetDisplayName(asset);const current=grouped.get(name)||{name,value:0,amount:0,symbol:asset.symbol||'',safeLabel:''};current.value+=asset.value||0;current.amount+=asset.amount||0;grouped.set(name,current)}));entries=[...grouped.values()]}
  const sorted=entries.sort((a,b)=>b.value-a.value);
  const total=sorted.reduce((sum,item)=>sum+item.value,0);
  const visible=sorted.slice(0,5);
  const rest=sorted.slice(5).reduce((sum,item)=>sum+item.value,0);
  if(rest>0)visible.push({name:'Other',value:rest,safeLabel:''});
  let cursor=0;
  const palette=PORTFOLIO_DONUT_PALETTES[portfolioPaletteIndex];
  portfolioDonutSlices=visible.map((item,index)=>{const start=cursor;cursor+=total?item.value/total*100:0;const color=item.name==='Other'?PORTFOLIO_DONUT_OTHER_COLOR:palette.colors[index%palette.colors.length];return {...item,index,start,end:cursor,percent:total?item.value/total*100:0,color}});
  const stops=portfolioDonutSlices.map(slice=>`${portfolioDonutHighlight<0||portfolioDonutHighlight===slice.index?slice.color:`${slice.color}30`} ${slice.start.toFixed(3)}% ${slice.end.toFixed(3)}%`);
  donut.style.background=total?`conic-gradient(${stops.join(',')})`:'rgba(255,255,255,.08)';
  const highlighted=portfolioDonutSlices[portfolioDonutHighlight];
  label.innerHTML=highlighted?`<b>${highlighted.percent.toFixed(0)}%</b><small>${escapeHtml(highlighted.name)}</small>${highlighted.safeLabel?`<small class="donut-safe-note">${escapeHtml(highlighted.safeLabel)}</small>`:''}`:(portfolioDonutMode==='wallets'?'Wallets':'Assets');
  if(tooltip){tooltip.hidden=!highlighted;tooltip.innerHTML=highlighted?`<strong>${portfolioDonutMode==='wallets'?'Wallet share':'Asset share'}</strong>${portfolioDonutSlices.map(slice=>{const holdings=portfolioDonutMode==='assets'&&Number.isFinite(slice.amount)?`${assetAmountDisplay({amount:slice.amount,symbol:slice.symbol})} ${escapeHtml(slice.symbol)} · `:'';return `<div class="portfolio-donut-tooltip-row${slice.index===portfolioDonutHighlight?' active':''}"><i style="background:${slice.color}"></i><span>${escapeHtml(slice.name)}</span><b>${slice.percent.toFixed(1)}%</b><small>${holdings}${escapeHtml(money(slice.value))}${slice.safeLabel?` · ${escapeHtml(slice.safeLabel)}`:''}</small></div>`}).join('')}`:''}
}
function renderTreasuryCapacity(){const donut=document.querySelector('#treasury-capacity-donut');const value=document.querySelector('#treasury-capacity-value');const cultBalance=document.querySelector('#treasury-cult-balance');if(!donut||!value)return;const current=Number(state.treasuryValueEth);const known=Number.isFinite(current);const cultKnown=Number.isFinite(state.treasuryCult);const cultText=cultKnown?`${state.treasuryCult.toLocaleString(undefined,{maximumFractionDigits:0})} CULT`:'Treasury CULT loading';const percent=known?Math.max(0,Math.min(100,current/TREASURY_PROPOSAL_CAPACITY_ETH*100)):0;donut.style.setProperty('--treasury-fill',`${percent}%`);donut.style.setProperty('--treasury-color',PORTFOLIO_DONUT_PALETTES[portfolioPaletteIndex].treasury);donut.dataset.cultInfo=cultText;value.textContent=known?`${current.toLocaleString(undefined,{maximumFractionDigits:2})} ETH`:'—';if(cultBalance)cultBalance.textContent=cultKnown?cultText:'— CULT';donut.setAttribute('aria-label',known?`Treasury holds ${cultText}, worth ${current.toFixed(2)} ETH, ${percent.toFixed(1)} percent of the 15.5 ETH proposal-capacity reference`:'Treasury CULT value loading')}
function cyclePortfolioPalette(){portfolioPaletteIndex=(portfolioPaletteIndex+1)%PORTFOLIO_DONUT_PALETTES.length;localStorage.setItem(PORTFOLIO_PALETTE_KEY,String(portfolioPaletteIndex));renderPortfolioDonut();renderTreasuryCapacity()}
function decorateWalletEditing(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);if(!wallet)return;card.querySelector('.inline-tag')?.remove();const editFields=card.querySelector('.edit-fields');if(editFields&&!editFields.querySelector('.remove-wallet')){const remove=document.createElement('button');remove.className='remove-wallet';remove.type='button';remove.textContent='Remove Wallet';remove.onclick=()=>{if(!confirm(`Remove ${wallet.label||short(wallet.address)} from the local watchlist?`))return;state.wallets=state.wallets.filter(item=>item.address.toLowerCase()!==wallet.address.toLowerCase());Object.keys(CHAINS).forEach(chain=>state.data.delete(`${wallet.address}:${chain}`));collapsedWallets.delete(wallet.address.toLowerCase());save();localStorage.setItem('cultFundsCollapsedWallets',JSON.stringify([...collapsedWallets]));render();toast('Wallet removed')};editFields.append(remove)}})}
function relativeActionTime(value){if(!value)return'Latest action';const seconds=Math.max(0,(Date.now()-new Date(value).getTime())/1000);if(seconds<60)return'Last action now';if(seconds<3600)return`Last action ${Math.floor(seconds/60)}m ago`;if(seconds<86400)return`Last action ${Math.floor(seconds/3600)}h ago`;if(seconds<2592000)return`Last action ${Math.floor(seconds/86400)}d ago`;return`Last action ${new Date(value).toLocaleDateString()}`}
function decorateSafeLinks(){const safePrefixes={ethereum:'eth',base:'base',polygon:'matic'};document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);const badge=card.querySelector('.pill.safe');if(!wallet||!badge||badge.closest('.safe-app-link'))return;const safeRow=walletRows(wallet).find(row=>row.safe);if(!safeRow)return;const safeRef=`${safePrefixes[safeRow.chain]}:${wallet.address}`;const link=document.createElement('a');link.className='safe-app-link';link.href=`https://app.safe.global/home?safe=${safeRef}`;link.target='_blank';link.rel='noopener noreferrer';link.title='Open this Safe';badge.replaceWith(link);link.append(badge);const badgeGroup=link.parentElement;const pending=safeRow.safe.pending;if(pending?.count>0){const status=document.createElement('a');status.className=`pill safe-pending ${pending.ready?'is-ready':'is-waiting'}`;status.href=`https://app.safe.global/transactions/queue?safe=${safeRef}`;status.target='_blank';status.rel='noopener noreferrer';status.textContent=pending.ready?`${pending.count} pending · ${pending.ready} ready`:`${pending.count} pending`;status.title=pending.items.map(item=>`Nonce ${item.nonce}: ${item.confirmations}/${item.required} signatures${item.ready?' · ready to execute':` · ${item.missing} needed`}`).join('\n');badgeGroup.append(status)}else if(pending?.latest){const latest=document.createElement('a');latest.className='pill safe-latest';const actionChain=pending.latest.chain||safeRow.chain;latest.href=pending.latest.safeTxHash?`https://app.safe.global/transactions/tx?id=multisig_${wallet.address}_${pending.latest.safeTxHash}&safe=${safeRef}`:pending.latest.txHash?`${CHAINS[actionChain].explorer.replace('/address/','/tx/')}${pending.latest.txHash}`:`https://app.safe.global/transactions/history?safe=${safeRef}`;latest.target='_blank';latest.rel='noopener noreferrer';latest.textContent=relativeActionTime(pending.latest.date);latest.title=pending.latest.safeTxHash?`Latest executed Safe transaction${pending.latest.nonce!=null?` · nonce ${pending.latest.nonce}`:''}`:`Latest ${CHAINS[actionChain].name} chain action`;badgeGroup.append(latest)}})}
function decorateSafeOwnerTooltips(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);const safeLink=card.querySelector('.safe-app-link');if(!wallet||!safeLink)return;const safeRow=walletRows(wallet).find(row=>row.safe);if(!safeRow)return;const safe=safeRow.safe;safeLink.title=`Open this Safe\nThreshold: ${safe.threshold} of ${safe.owners.length}\nOwners:\n${safe.owners.map(owner=>{const alias=ownerAliases[owner.toLowerCase()];const name=cachedEnsName(owner);return [alias,name,owner].filter(Boolean).join(' · ')}).join('\n')}`})}
function decorateEnsNames(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);if(!wallet)return;const address=card.querySelector('.wallet-title .address');const existing=card.querySelector('.wallet-title .ens-name');const name=cachedEnsName(wallet.address);existing?.remove();if(name&&address){const badge=document.createElement('span');badge.className='ens-name';badge.textContent=name;badge.title=`ENS name for ${wallet.address}`;const copy=address.parentElement.querySelector('.inline-copy');(copy||address).insertAdjacentElement('afterend',badge)}card.querySelectorAll('.assets .asset-row').forEach(row=>{if(!row.firstElementChild?.textContent.trim().startsWith('Safe owners'))return;row.querySelectorAll('a.address').forEach(link=>{const owner=link.href.split('/').filter(Boolean).pop();if(!ethers.utils.isAddress(owner))return;const ownerName=cachedEnsName(owner);link.textContent=ownerName||short(owner);link.classList.toggle('has-ens',!!ownerName);link.title=ownerName?`${ownerName}\n${owner}`:owner})})});document.querySelectorAll('#overview-asset-list [data-wallet-anchor]').forEach(link=>{const address=String(link.dataset.walletAnchor||'').replace(/^wallet-/,'');if(!ethers.utils.isAddress(address))return;const wallet=state.wallets.find(item=>item.address.toLowerCase()===address.toLowerCase());const name=cachedEnsName(address);const useEns=!wallet?.label&&!!name;if(useEns)link.textContent=name;link.classList.toggle('has-ens',useEns)});document.querySelectorAll('#overview-empty-wallet-links a').forEach(link=>{const address=link.href.split('/').filter(Boolean).pop();if(!ethers.utils.isAddress(address))return;const wallet=state.wallets.find(item=>item.address.toLowerCase()===address.toLowerCase());const name=cachedEnsName(address);const useEns=!wallet?.label&&!!name;if(useEns)link.textContent=name;link.classList.toggle('has-ens',useEns)});decorateSafeOwnerTooltips()}
async function writeClipboardText(value){try{if(navigator.clipboard?.writeText){await navigator.clipboard.writeText(value);return true}}catch{}const input=document.createElement('textarea');input.value=value;input.setAttribute('readonly','');input.style.position='fixed';input.style.opacity='0';document.body.append(input);input.select();let copied=false;try{copied=document.execCommand('copy')}catch{}input.remove();return copied}
function copiedAddressFeedback(button,address){writeClipboardText(address).then(copied=>{if(!copied){toast('Could not copy address');return}button.classList.add('copied');button.title='Copied';button.dataset.copyFeedback='Copied';setTimeout(()=>{button.classList.remove('copied');button.title='Copy address';delete button.dataset.copyFeedback},1100)})}
function addAddressCopyControl(link,address,wrapperClass='copyable-address'){if(!link||!ethers.utils.isAddress(address))return;let wrapper=link.closest(`.${wrapperClass}`);if(!wrapper){wrapper=document.createElement('span');wrapper.className=wrapperClass;link.insertAdjacentElement('beforebegin',wrapper);wrapper.append(link)}let button=wrapper.querySelector('.address-copy');if(!button){button=document.createElement('button');button.type='button';button.className='inline-control address-copy';button.innerHTML=COPY_ICON_SVG;button.title='Copy address';button.setAttribute('aria-label',`Copy ${address}`);wrapper.append(button)}button.onclick=event=>{event.preventDefault();event.stopPropagation();copiedAddressFeedback(button,address)}}
function decorateCopyableAddresses(){document.querySelectorAll('.wallet-card').forEach(card=>{const wallet=walletFromCard(card);const address=card.querySelector('.wallet-title .address');if(wallet&&address){let line=address.closest('.wallet-address-line');if(!line){line=document.createElement('span');line.className='wallet-address-line';address.insertAdjacentElement('beforebegin',line);line.append(address);const existingCopy=address.parentElement===line?card.querySelector('.inline-copy'):null;if(existingCopy&&!line.contains(existingCopy))line.append(existingCopy)}const copy=card.querySelector('.inline-copy');if(copy&&!line.contains(copy))line.append(copy);const ens=card.querySelector('.wallet-title .ens-name');if(ens&&!line.contains(ens))line.append(ens);if(copy)copy.onclick=event=>{event.preventDefault();event.stopPropagation();copiedAddressFeedback(copy,wallet.address)}}card.querySelectorAll('.assets .asset-row').forEach(row=>{if(!row.firstElementChild?.textContent.trim().startsWith('Safe owners'))return;row.classList.add('safe-owner-row');const list=row.lastElementChild;list?.classList.add('safe-owner-list');row.querySelectorAll('a.address').forEach(link=>{const owner=link.href.split('/').filter(Boolean).pop();addAddressCopyControl(link,owner,'owner-address-line')})})});document.querySelectorAll('#overview-asset-list [data-wallet-anchor]').forEach(link=>{const address=String(link.dataset.walletAnchor||'').replace(/^wallet-/,'');addAddressCopyControl(link,address,'holder-address-line')});document.querySelectorAll('#overview-empty-wallet-links a').forEach(link=>{const address=link.href.split('/').filter(Boolean).pop();addAddressCopyControl(link,address,'empty-address-line')})}
