function delegationForAddress(address){
  if(!ethers.utils.isAddress(address||''))return null;
  return state.data.get(`${ethers.utils.getAddress(address)}:ethereum`)?.delegation||null;
}
function delegationBalanceLabel(delegation){
  try{return `${Number(ethers.utils.formatUnits(delegation.balance||'0',18)).toLocaleString(undefined,{maximumFractionDigits:2})} dCULT`}
  catch{return 'dCULT balance unavailable'}
}
function delegationTooltip(delegation){
  const lines=[delegation.label,delegationBalanceLabel(delegation),delegation.currentState];
  if(delegation.key==='delegated-elsewhere'&&ethers.utils.isAddress(delegation.delegatee||''))lines.push(`Delegatee: ${ethers.utils.getAddress(delegation.delegatee)}`);
  if(delegation.nextStep)lines.push(`Needed: ${delegation.nextStep}`);
  return lines.filter(Boolean).join('\n');
}
function addressFromIdentityWrapper(wrapper){
  const anchored=wrapper.querySelector('[data-wallet-anchor]')?.dataset.walletAnchor?.replace(/^wallet-/,'');
  if(ethers.utils.isAddress(anchored||''))return anchored;
  const href=wrapper.querySelector('a.address')?.href||wrapper.querySelector('a')?.href||'';
  const candidate=href.split('/').filter(Boolean).pop();
  return ethers.utils.isAddress(candidate||'')?candidate:'';
}
function decorateVotingReadiness(){
  document.querySelectorAll('.wallet-card').forEach(card=>{
    const wallet=walletFromCard(card);
    const delegation=wallet?delegationForAddress(wallet.address):null;
    const pills=card.querySelector('.chain-pills');
    pills?.querySelector('.voting-readiness')?.remove();
    if(!delegation)return;
    window.CultGovernanceLiveState?.prime?.(wallet.address,{balance:delegation.balance,delegatee:delegation.delegatee,isGuardian:delegation.isGuardian});
    card.dataset.votingReadiness=delegation.key;
    card.dataset.votingReadinessLabel=delegation.label;
  });
  document.querySelectorAll('.owner-address-line,.holder-address-line,.empty-address-line').forEach(wrapper=>{
    if(wrapper.querySelector('.address-voting-readiness'))return;
    const address=addressFromIdentityWrapper(wrapper);
    const delegation=delegationForAddress(address);
    if(!delegation||(delegation.key==='not-eligible'&&!delegation.isGuardian))return;
    const marker=document.createElement('span');
    marker.className=`address-voting-readiness readiness-${delegation.key}`;
    marker.textContent=delegation.compactLabel;
    marker.title=delegationTooltip(delegation);
    marker.setAttribute('aria-label',`${delegation.label}. ${delegationBalanceLabel(delegation)}`);
    wrapper.append(marker);
  });
}
