function lpExposureIdentity(symbol,chain){const normalized=String(symbol||'').toUpperCase();if(chain==='ethereum'&&normalized==='ENA')return{address:ENA_TOKEN_ADDRESS,name:'Ethena',icon:null};if(chain==='ethereum'&&(normalized==='WETH'||normalized==='ETH'))return{address:WETH_TOKEN_ADDRESS,name:'Wrapped Ether',icon:null};if(chain==='ethereum'&&normalized==='CULT')return{address:CULT_TOKEN_ADDRESS,name:'Cult DAO',icon:null};let match=null;state.data.forEach(row=>(row.assets||[]).forEach(asset=>{if(!match&&asset.chain===chain&&String(asset.symbol||'').toUpperCase()===normalized&&!asset.lp)match={address:asset.address,name:asset.name||symbol,icon:asset.icon||null}}));return match||{address:`lp-underlying-${normalized.toLowerCase()}`,name:symbol,icon:null}}
